import React, { useEffect } from 'react';
import { Linking, Platform } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const DeepLinkHandler = () => {
  const navigation = useNavigation();

  useEffect(() => {
    const handleDeepLink = (event) => {
      const url = event.url;
      if (url) {
        parseAndNavigate(url);
      }
    };

    // Initial check for deep link when the app is launched from a deep link
    Linking.getInitialURL().then(url => {
      if (url) {
        parseAndNavigate(url);
      }
    }).catch(err => console.error('An error occurred', err));

    // Listen for deep links when the app is already running
    Linking.addEventListener('url', handleDeepLink);

    // Clean up the event listener
    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  }, [navigation]);

  const parseAndNavigate = (url) => {
    const scheme = 'myapp'; // Your app's custom URL scheme
    if (!url.startsWith(`${scheme}://`)) {
      return;
    }

    // Remove the scheme to get the path and query
    const pathAndQuery = url.replace(`${scheme}://`, '');

    // Split into path segments
    const parts = pathAndQuery.split('/');
    const mainPath = parts[0];

    switch (mainPath) {
      case 'profile':
        if (parts[1]) {
          const userId = parts[1];
          navigation.navigate('ProfileScreen', { userId: userId });
        }
        break;
      case 'payment':
        if (parts[1] === 'confirm') {
          // You might extract further details from query parameters if available
          // For simplicity, we just navigate to a confirmation screen
          navigation.navigate('PaymentConfirmationScreen');
        }
        break;
      // Add more cases for other deep link paths
      case 'settings':
        navigation.navigate('SettingsScreen');
        break;
      default:
        // Handle unknown or invalid paths, e.g., navigate to a home screen
        navigation.navigate('HomeScreen');
        break;
    }
  };

  return null; // This component doesn't render anything visually
};

export default DeepLinkHandler;

